// Standard dartboard segment order (clockwise from top)
export const BOARD_SEGMENTS = [20, 1, 18, 4, 13, 6, 10, 15, 2, 17, 3, 19, 7, 16, 8, 11, 14, 9, 12, 5];

// Dartboard dimensions (in meters, scaled from standard 451mm diameter)
const BOARD_RADIUS = 0.2255; // 451mm / 2
const DOUBLE_OUTER = 0.170;
const DOUBLE_INNER = 0.162;
const TRIPLE_OUTER = 0.107;
const TRIPLE_INNER = 0.099;
const OUTER_BULL = 0.0159; // outer bull radius
const INNER_BULL = 0.00635; // bullseye radius
const WIRE_WIDTH = 0.001;

// Segment colors — alternating black/white with red/green accents
const SEGMENT_COLORS = {
  black: '#0a0a1a',
  white: '#1a1a2a',
  red: '#cc0033',
  green: '#009933',
  bullRed: '#cc0033',
  bullGreen: '#009933',
  wire: '#444466',
  surround: '#111122',
  neonCyan: '#00ffff',
  neonMagenta: '#ff00ff',
};

export interface ScoreResult {
  segment: number;   // 1-20, or 25 for bull
  multiplier: number; // 1=single, 2=double, 3=triple, 25=outer bull, 50=inner bull
  total: number;
  x: number;
  y: number;
  label: string;
}

export function getScoreForPosition(x: number, y: number): ScoreResult {
  const dist = Math.sqrt(x * x + y * y);
  let angle = Math.atan2(x, y); // Note: x,y not y,x — 20 is at top
  if (angle < 0) angle += Math.PI * 2;

  // Bullseye check
  if (dist <= INNER_BULL) {
    return { segment: 25, multiplier: 2, total: 50, x, y, label: 'BULLSEYE!' };
  }
  if (dist <= OUTER_BULL) {
    return { segment: 25, multiplier: 1, total: 25, x, y, label: 'BULL' };
  }

  // Off the board
  if (dist > BOARD_RADIUS) {
    return { segment: 0, multiplier: 0, total: 0, x, y, label: 'MISS' };
  }

  // Determine segment
  const segmentAngle = (Math.PI * 2) / 20;
  const halfSeg = segmentAngle / 2;
  // Adjust angle so segment 20 is centered at top (angle = 0)
  let adjustedAngle = angle + halfSeg;
  if (adjustedAngle >= Math.PI * 2) adjustedAngle -= Math.PI * 2;
  const segIndex = Math.floor(adjustedAngle / segmentAngle);
  const segment = BOARD_SEGMENTS[segIndex] || 20;

  // Determine ring
  let multiplier = 1;
  let label = `${segment}`;
  if (dist >= DOUBLE_INNER && dist <= DOUBLE_OUTER) {
    multiplier = 2;
    label = `D${segment}`;
  } else if (dist >= TRIPLE_INNER && dist <= TRIPLE_OUTER) {
    multiplier = 3;
    label = `T${segment}`;
  }

  return { segment, multiplier, total: segment * multiplier, x, y, label };
}

export function createDartboard(world: World): Group {
  const board = new Group();

  // Surround ring (dark background beyond scoring area)
  const surroundGeo = new RingGeometry(BOARD_RADIUS, BOARD_RADIUS + 0.04, 64);
  const surroundMat = new MeshStandardMaterial({
    color: SEGMENT_COLORS.surround,
    emissive: new Color(SEGMENT_COLORS.surround),
    emissiveIntensity: 0.3,
    side: DoubleSide,
  });
  const surround = new Mesh(surroundGeo, surroundMat);
  board.add(surround);

  // Outer frame — glowing neon ring
  const frameGeo = new RingGeometry(BOARD_RADIUS + 0.04, BOARD_RADIUS + 0.05, 64);
  const frameMat = new MeshBasicMaterial({
    color: SEGMENT_COLORS.neonCyan,
    transparent: true,
    opacity: 0.8,
    side: DoubleSide,
  });
  const frame = new Mesh(frameGeo, frameMat);
  board.add(frame);

  // Glow ring
  const glowGeo = new RingGeometry(BOARD_RADIUS + 0.05, BOARD_RADIUS + 0.08, 64);
  const glowMat = new MeshBasicMaterial({
    color: SEGMENT_COLORS.neonCyan,
    transparent: true,
    opacity: 0.2,
    blending: AdditiveBlending,
    side: DoubleSide,
  });
  const glow = new Mesh(glowGeo, glowMat);
  board.add(glow);

  // Draw 20 segments
  const segmentAngle = (Math.PI * 2) / 20;
  for (let i = 0; i < 20; i++) {
    const startAngle = i * segmentAngle - segmentAngle / 2 - Math.PI / 2;
    const isEven = i % 2 === 0;

    // Outer single (between double and triple)
    drawSegmentRing(board, DOUBLE_INNER, TRIPLE_OUTER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.black : SEGMENT_COLORS.white);

    // Inner single (between triple and bull)
    drawSegmentRing(board, TRIPLE_INNER, OUTER_BULL, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.black : SEGMENT_COLORS.white);

    // Double ring
    drawSegmentRing(board, DOUBLE_OUTER, DOUBLE_INNER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.red : SEGMENT_COLORS.green);

    // Triple ring
    drawSegmentRing(board, TRIPLE_OUTER, TRIPLE_INNER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.red : SEGMENT_COLORS.green);

    // Single outer (between double and board edge)
    drawSegmentRing(board, BOARD_RADIUS, DOUBLE_OUTER, startAngle, segmentAngle,
      isEven ? SEGMENT_COLORS.black : SEGMENT_COLORS.white);

    // Segment number label — canvas texture for sharp text
    const labelAngle = i * segmentAngle - Math.PI / 2;
    const labelDist = BOARD_RADIUS + 0.03;
    const labelX = Math.cos(labelAngle) * labelDist;
    const labelY = Math.sin(labelAngle) * labelDist;

    const numLabel = createNumberLabel(BOARD_SEGMENTS[i]);
    numLabel.position.set(labelX, labelY, 0.002);
    board.add(numLabel);
  }

  // Outer bull
  const outerBullGeo = new CircleGeometry(OUTER_BULL, 32);
  const outerBullMat = new MeshStandardMaterial({
    color: SEGMENT_COLORS.bullGreen,
    emissive: new Color(SEGMENT_COLORS.bullGreen),
    emissiveIntensity: 0.5,
    side: DoubleSide,
  });
  const outerBull = new Mesh(outerBullGeo, outerBullMat);
  outerBull.position.z = 0.001;
  board.add(outerBull);

  // Inner bull (bullseye)
  const innerBullGeo = new CircleGeometry(INNER_BULL, 32);
  const innerBullMat = new MeshStandardMaterial({
    color: SEGMENT_COLORS.bullRed,
    emissive: new Color(SEGMENT_COLORS.bullRed),
    emissiveIntensity: 0.8,
    side: DoubleSide,
  });
  const innerBull = new Mesh(innerBullGeo, innerBullMat);
  innerBull.position.z = 0.002;
  board.add(innerBull);

  // Bullseye glow
  const bullGlowGeo = new CircleGeometry(INNER_BULL * 2, 32);
  const bullGlowMat = new MeshBasicMaterial({
    color: '#ff3333',
    transparent: true,
    opacity: 0.15,
    blending: AdditiveBlending,
    side: DoubleSide,
  });
  const bullGlow = new Mesh(bullGlowGeo, bullGlowMat);
  bullGlow.position.z = 0.003;
  board.add(bullGlow);

  // Wire rings
  drawWireRing(board, DOUBLE_OUTER);
  drawWireRing(board, DOUBLE_INNER);
  drawWireRing(board, TRIPLE_OUTER);
  drawWireRing(board, TRIPLE_INNER);
  drawWireRing(board, OUTER_BULL);
  drawWireRing(board, INNER_BULL);

  // Wire spokes (segment dividers)
  for (let i = 0; i < 20; i++) {
    const angle = i * segmentAngle - segmentAngle / 2 - Math.PI / 2;
    drawWireSpoke(board, angle, INNER_BULL, BOARD_RADIUS);
  }

  // Board backing (solid cylinder behind the face)
  const backGeo = new CylinderGeometry(BOARD_RADIUS + 0.04, BOARD_RADIUS + 0.04, 0.04, 64);
  const backMat = new MeshStandardMaterial({
    color: '#0a0a15',
    roughness: 0.9,
  });
  const back = new Mesh(backGeo, backMat);
  back.rotation.x = Math.PI / 2;
  back.position.z = -0.02;
  board.add(back);

  return board;
}

function drawSegmentRing(
  parent: Group, outerR: number, innerR: number,
  startAngle: number, arcAngle: number, color: string
) {
  const segments = 16;
  const geo = new RingGeometry(innerR, outerR, segments, 1, startAngle, arcAngle);
  const mat = new MeshStandardMaterial({
    color,
    emissive: new Color(color),
    emissiveIntensity: 0.3,
    side: DoubleSide,
    roughness: 0.7,
  });
  const mesh = new Mesh(geo, mat);
  mesh.position.z = 0.001;
  parent.add(mesh);
}

function drawWireRing(parent: Group, radius: number) {
  const segments = 64;
  const points: number[] = [];
  for (let i = 0; i <= segments; i++) {
    const a = (i / segments) * Math.PI * 2;
    points.push(Math.cos(a) * radius, Math.sin(a) * radius, 0.003);
  }
  const geo = new BufferGeometry();
  geo.setAttribute('position', new Float32BufferAttribute(points, 3));
  const mat = new LineBasicMaterial({ color: SEGMENT_COLORS.wire, transparent: true, opacity: 0.6 });
  const line = new LineSegments(geo, mat);
  // Convert to line loop manually
  const loopGeo = new BufferGeometry();
  const loopPts: number[] = [];
  for (let i = 0; i < segments; i++) {
    const a1 = (i / segments) * Math.PI * 2;
    const a2 = ((i + 1) / segments) * Math.PI * 2;
    loopPts.push(Math.cos(a1) * radius, Math.sin(a1) * radius, 0.003);
    loopPts.push(Math.cos(a2) * radius, Math.sin(a2) * radius, 0.003);
  }
  loopGeo.setAttribute('position', new Float32BufferAttribute(loopPts, 3));
  const loop = new LineSegments(loopGeo, mat);
  parent.add(loop);
}

function drawWireSpoke(parent: Group, angle: number, innerR: number, outerR: number) {
  const geo = new BufferGeometry();
  const pts = [
    Math.cos(angle) * innerR, Math.sin(angle) * innerR, 0.003,
    Math.cos(angle) * outerR, Math.sin(angle) * outerR, 0.003,
  ];
  geo.setAttribute('position', new Float32BufferAttribute(pts, 3));
  const mat = new LineBasicMaterial({ color: SEGMENT_COLORS.wire, transparent: true, opacity: 0.6 });
  parent.add(new LineSegments(geo, mat));
}

function createNumberLabel(num: number): Mesh {
  const size = 64;
  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const ctx2d = canvas.getContext('2d')!;

  ctx2d.clearRect(0, 0, size, size);
  ctx2d.font = 'bold 40px Arial, sans-serif';
  ctx2d.textAlign = 'center';
  ctx2d.textBaseline = 'middle';

  // Outer glow
  ctx2d.shadowColor = '#00ffff';
  ctx2d.shadowBlur = 8;
  ctx2d.fillStyle = '#00ffff';
  ctx2d.fillText(String(num), size / 2, size / 2);

  // Crisp white fill on top
  ctx2d.shadowBlur = 0;
  ctx2d.fillStyle = '#ffffff';
  ctx2d.fillText(String(num), size / 2, size / 2);

  const texture = new CanvasTexture(canvas);
  texture.minFilter = NearestFilter;
  texture.magFilter = NearestFilter;
  if ('colorSpace' in texture) {
    (texture as any).colorSpace = SRGBColorSpace;
  }

  const geo = new PlaneGeometry(0.025, 0.025);
  const mat = new MeshBasicMaterial({
    map: texture,
    transparent: true,
    depthWrite: false,
    side: DoubleSide,
  });

  return new Mesh(geo, mat);
}

// Dart throwing and flight
import {
  World,
  Group,
  Mesh,
  CylinderGeometry,
  ConeGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Color,
  Vector3,
  AdditiveBlending,
  BufferGeometry,
  Float32BufferAttribute,
  LineSegments,
  LineBasicMaterial,
} from '@iwsdk/core';

import { getScoreForPosition, ScoreResult } from './dartboard';
import { AudioManager } from './audio';
import { EffectsManager } from './effects';
import { DartSkinManager } from './skins';

interface Dart {
  group: Group;
  velocity: Vector3;
  state: 'flying' | 'stuck' | 'idle';
  trail: Vector3[];
  trailMesh: LineSegments | null;
  trailColor: string;
}

export class DartManager {
  private world: World;
  private boardGroup: Group;
  private audio: AudioManager;
  private effects: EffectsManager;
  private skinManager: DartSkinManager | null = null;
  private darts: Dart[] = [];
  private maxDarts = 3;
  private throwCount = 0;

  public onDartHit: ((result: ScoreResult) => void) | null = null;

  constructor(world: World, boardGroup: Group, audio: AudioManager, effects: EffectsManager) {
    this.world = world;
    this.boardGroup = boardGroup;
    this.audio = audio;
    this.effects = effects;
  }

  setSkinManager(skinManager: DartSkinManager) {
    this.skinManager = skinManager;
  }

  canThrow(): boolean {
    return this.throwCount < this.maxDarts;
  }

  throwDart(aimX: number, aimY: number, power: number) {
    if (!this.canThrow()) return;

    // Natural scatter
    const scatter = 0.015 * (1 - power * 0.5) + 0.005;
    const finalX = aimX + (Math.random() - 0.5) * scatter;
    const finalY = aimY + (Math.random() - 0.5) * scatter;

    // Create dart mesh
    const dart = this.createDartMesh();

    const startPos = new Vector3(0, 1.6, -0.3);
    dart.group.position.copy(startPos);
    this.world.scene.add(dart.group);

    const targetPos = new Vector3(
      this.boardGroup.position.x + finalX,
      this.boardGroup.position.y + finalY,
      this.boardGroup.position.z + 0.02
    );

    const direction = targetPos.clone().sub(startPos);
    const distance = direction.length();
    const flightTime = 0.15 + 0.15 * (1 - power);
    const speed = distance / flightTime;
    direction.normalize().multiplyScalar(speed);

    dart.velocity = direction;
    dart.state = 'flying';
    this.darts.push(dart);
    this.throwCount++;

    this.audio.playThrow(power);

    const result = getScoreForPosition(finalX, finalY);

    setTimeout(() => {
      if (dart.state === 'flying') {
        dart.state = 'stuck';
        dart.group.position.copy(targetPos);
        dart.group.rotation.x = 0;
        dart.velocity.set(0, 0, 0);

        if (result.total > 0) {
          this.audio.playHit(result);
        } else {
          this.audio.playMiss();
        }

        if (this.onDartHit) {
          this.onDartHit(result);
        }
      }
    }, flightTime * 1000);
  }

  private createDartMesh(): Dart {
    // Use skin manager if available
    if (this.skinManager) {
      const group = this.skinManager.createDartMesh();
      return {
        group,
        velocity: new Vector3(),
        state: 'idle',
        trail: [],
        trailMesh: null,
        trailColor: this.skinManager.currentSkin.glowColor,
      };
    }

    // Fallback default dart
    const group = new Group();

    const barrelGeo = new CylinderGeometry(0.003, 0.004, 0.05, 8);
    const barrelMat = new MeshStandardMaterial({
      color: '#00ffff',
      emissive: new Color('#00ffff'),
      emissiveIntensity: 0.6,
      metalness: 0.8,
      roughness: 0.2,
    });
    const barrel = new Mesh(barrelGeo, barrelMat);
    barrel.rotation.x = Math.PI / 2;
    group.add(barrel);

    const tipGeo = new ConeGeometry(0.003, 0.02, 8);
    const tipMat = new MeshStandardMaterial({
      color: '#ffffff',
      emissive: new Color('#ffffff'),
      emissiveIntensity: 0.4,
      metalness: 0.9,
    });
    const tip = new Mesh(tipGeo, tipMat);
    tip.rotation.x = -Math.PI / 2;
    tip.position.z = -0.035;
    group.add(tip);

    for (let i = 0; i < 4; i++) {
      const flightGeo = new CylinderGeometry(0, 0.008, 0.02, 3);
      const flightMat = new MeshBasicMaterial({
        color: '#ff00ff',
        transparent: true,
        opacity: 0.7,
        side: 2,
      });
      const flight = new Mesh(flightGeo, flightMat);
      flight.rotation.x = Math.PI / 2;
      flight.rotation.z = (i / 4) * Math.PI * 2;
      flight.position.z = 0.03;
      group.add(flight);
    }

    const glowGeo = new CylinderGeometry(0.008, 0.008, 0.06, 8);
    const glowMat = new MeshBasicMaterial({
      color: '#00ffff',
      transparent: true,
      opacity: 0.15,
      blending: AdditiveBlending,
    });
    const glowMesh = new Mesh(glowGeo, glowMat);
    glowMesh.rotation.x = Math.PI / 2;
    group.add(glowMesh);

    return {
      group,
      velocity: new Vector3(),
      state: 'idle',
      trail: [],
      trailMesh: null,
      trailColor: '#00ffff',
    };
  }

  update(dt: number) {
    for (const dart of this.darts) {
      if (dart.state === 'flying') {
        dart.velocity.y -= 0.5 * dt;
        dart.group.position.add(dart.velocity.clone().multiplyScalar(dt));

        if (dart.velocity.lengthSq() > 0.01) {
          const dir = dart.velocity.clone().normalize();
          dart.group.lookAt(dart.group.position.clone().add(dir));
        }

        dart.trail.push(dart.group.position.clone());
        if (dart.trail.length > 20) dart.trail.shift();
        this.updateTrail(dart);

        if (dart.group.position.z < -3) {
          dart.state = 'stuck';
          dart.velocity.set(0, 0, 0);
        }
      }
    }
  }

  private updateTrail(dart: Dart) {
    if (dart.trailMesh) {
      this.world.scene.remove(dart.trailMesh);
      dart.trailMesh.geometry.dispose();
    }

    if (dart.trail.length < 2) return;

    const pts: number[] = [];
    for (let i = 0; i < dart.trail.length - 1; i++) {
      pts.push(dart.trail[i].x, dart.trail[i].y, dart.trail[i].z);
      pts.push(dart.trail[i + 1].x, dart.trail[i + 1].y, dart.trail[i + 1].z);
    }
    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute(pts, 3));
    const mat = new LineBasicMaterial({
      color: dart.trailColor,
      transparent: true,
      opacity: 0.3,
    });
    dart.trailMesh = new LineSegments(geo, mat);
    this.world.scene.add(dart.trailMesh);
  }

  clearDarts() {
    for (const dart of this.darts) {
      this.world.scene.remove(dart.group);
      if (dart.trailMesh) {
        this.world.scene.remove(dart.trailMesh);
        dart.trailMesh.geometry.dispose();
      }
    }
    this.darts = [];
    this.throwCount = 0;
  }
}

// Audio manager — procedural Web Audio effects
export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private ambientOsc: OscillatorNode | null = null;
  private ambientLfo: OscillatorNode | null = null;

  masterVolume = 0.7;
  sfxVolume = 0.8;
  musicVolume = 0.3;

  private ensureContext() {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = this.masterVolume;
      this.masterGain.connect(this.ctx.destination);

      this.sfxGain = this.ctx.createGain();
      this.sfxGain.gain.value = this.sfxVolume;
      this.sfxGain.connect(this.masterGain);

      this.musicGain = this.ctx.createGain();
      this.musicGain.gain.value = this.musicVolume;
      this.musicGain.connect(this.masterGain);

      this.startAmbient();
    }
    if (this.ctx.state === 'suspended') this.ctx.resume();
    return this.ctx;
  }

  private startAmbient() {
    if (!this.ctx || !this.musicGain) return;

    // Deep ambient drone
    const osc = this.ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 55;

    const lfo = this.ctx.createOscillator();
    lfo.type = 'sine';
    lfo.frequency.value = 0.2;
    const lfoGain = this.ctx.createGain();
    lfoGain.gain.value = 3;
    lfo.connect(lfoGain);
    lfoGain.connect(osc.frequency);
    lfo.start();

    // Pad
    const pad = this.ctx.createOscillator();
    pad.type = 'triangle';
    pad.frequency.value = 110;
    const padGain = this.ctx.createGain();
    padGain.gain.value = 0.08;
    pad.connect(padGain);
    padGain.connect(this.musicGain);
    pad.start();

    const oscGain = this.ctx.createGain();
    oscGain.gain.value = 0.12;
    osc.connect(oscGain);
    oscGain.connect(this.musicGain);
    osc.start();

    this.ambientOsc = osc;
    this.ambientLfo = lfo;
  }

  setVolume(type: 'master' | 'sfx' | 'music', value: number) {
    value = Math.max(0, Math.min(1, value));
    switch (type) {
      case 'master':
        this.masterVolume = value;
        if (this.masterGain) this.masterGain.gain.value = value;
        break;
      case 'sfx':
        this.sfxVolume = value;
        if (this.sfxGain) this.sfxGain.gain.value = value;
        break;
      case 'music':
        this.musicVolume = value;
        if (this.musicGain) this.musicGain.gain.value = value;
        break;
    }
  }

  playThrow(power: number) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    // Whoosh — filtered noise
    const bufferSize = ctx.sampleRate * 0.15;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * (1 - i / bufferSize);
    }
    const src = ctx.createBufferSource();
    src.buffer = buffer;

    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 800 + power * 1200;
    filter.Q.value = 2;

    const gain = ctx.createGain();
    gain.gain.value = 0.3 + power * 0.3;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

    src.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    src.start();
  }

  playHit(result: { total: number; multiplier: number; segment: number }) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    // Thud/stick sound
    const osc = ctx.createOscillator();
    osc.type = 'square';
    osc.frequency.value = 200;
    osc.frequency.exponentialRampToValueAtTime(80, ctx.currentTime + 0.05);

    const gain = ctx.createGain();
    gain.gain.value = 0.4;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.08);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.1);

    // Bonus chime for high scores
    if (result.multiplier >= 2 || result.segment === 25) {
      setTimeout(() => this.playScoreChime(result), 50);
    }
  }

  private playScoreChime(result: { total: number; multiplier: number; segment: number }) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const baseFreq = result.segment === 25 ? 880 : (result.multiplier === 3 ? 660 : 523);
    const notes = result.segment === 25 && result.multiplier === 2
      ? [baseFreq, baseFreq * 1.25, baseFreq * 1.5, baseFreq * 2]
      : [baseFreq, baseFreq * 1.25, baseFreq * 1.5];

    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const gain = ctx.createGain();
      gain.gain.value = 0;
      gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.08);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + i * 0.08 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.08 + 0.2);

      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.08);
      osc.stop(ctx.currentTime + i * 0.08 + 0.25);
    });
  }

  playMiss() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    // Dull thud
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 100;
    osc.frequency.exponentialRampToValueAtTime(50, ctx.currentTime + 0.1);

    const gain = ctx.createGain();
    gain.gain.value = 0.3;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.2);
  }

  playGameStart() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const notes = [262, 330, 392, 523];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'triangle';
      osc.frequency.value = freq;

      const gain = ctx.createGain();
      gain.gain.value = 0;
      gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.1);
      gain.gain.linearRampToValueAtTime(0.15, ctx.currentTime + i * 0.1 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.1 + 0.3);

      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.1);
      osc.stop(ctx.currentTime + i * 0.1 + 0.4);
    });
  }

  playGameOver(won: boolean) {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    if (won) {
      const notes = [523, 659, 784, 1047];
      notes.forEach((freq, i) => {
        const osc = ctx.createOscillator();
        osc.type = 'sawtooth';
        osc.frequency.value = freq;

        const filter = ctx.createBiquadFilter();
        filter.type = 'lowpass';
        filter.frequency.value = 2000;

        const gain = ctx.createGain();
        gain.gain.value = 0;
        gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.12);
        gain.gain.linearRampToValueAtTime(0.12, ctx.currentTime + i * 0.12 + 0.03);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.12 + 0.5);

        osc.connect(filter);
        filter.connect(gain);
        gain.connect(this.sfxGain!);
        osc.start(ctx.currentTime + i * 0.12);
        osc.stop(ctx.currentTime + i * 0.12 + 0.6);
      });
    } else {
      const notes = [400, 350, 300, 200];
      notes.forEach((freq, i) => {
        const osc = ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.value = freq;

        const gain = ctx.createGain();
        gain.gain.value = 0;
        gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.15);
        gain.gain.linearRampToValueAtTime(0.15, ctx.currentTime + i * 0.15 + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.15 + 0.4);

        osc.connect(gain);
        gain.connect(this.sfxGain!);
        osc.start(ctx.currentTime + i * 0.15);
        osc.stop(ctx.currentTime + i * 0.15 + 0.5);
      });
    }
  }

  playAchievement() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const notes = [523, 659, 784, 1047, 1319];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;

      const gain = ctx.createGain();
      gain.gain.value = 0;
      gain.gain.setValueAtTime(0, ctx.currentTime + i * 0.06);
      gain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + i * 0.06 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + i * 0.06 + 0.3);

      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.06);
      osc.stop(ctx.currentTime + i * 0.06 + 0.35);
    });
  }

  playButtonClick() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 600;

    const gain = ctx.createGain();
    gain.gain.value = 0.1;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.05);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.06);
  }

  playTurnChange() {
    const ctx = this.ensureContext();
    if (!this.sfxGain) return;

    const osc = ctx.createOscillator();
    osc.type = 'triangle';
    osc.frequency.value = 440;

    const osc2 = ctx.createOscillator();
    osc2.type = 'triangle';
    osc2.frequency.value = 554;

    const gain = ctx.createGain();
    gain.gain.value = 0.08;
    gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

    osc.connect(gain);
    osc2.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc2.start(ctx.currentTime + 0.06);
    osc.stop(ctx.currentTime + 0.1);
    osc2.stop(ctx.currentTime + 0.16);
  }
}

// Holodeck environment
import {
  World,
  Mesh,
  Group,
  PlaneGeometry,
  BoxGeometry,
  SphereGeometry,
  TorusGeometry,
  ConeGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  Color,
  Fog,
  AmbientLight,
  PointLight,
  DirectionalLight,
  DoubleSide,
  AdditiveBlending,
  MathUtils,
  Vector3,
} from '@iwsdk/core';

export function createEnvironment(world: World) {
  // Fog
  world.scene.fog = new Fog(0x000011, 5, 30);

  // Ambient light
  const ambient = new AmbientLight(0x222244, 0.5);
  world.scene.add(ambient);

  // Key lights
  const keyLight = new DirectionalLight(0x88aaff, 0.3);
  keyLight.position.set(2, 4, 1);
  world.scene.add(keyLight);

  // Board spotlight
  const boardLight = new PointLight(0x00ffff, 2, 5);
  boardLight.position.set(0, 2.5, -2.2);
  world.scene.add(boardLight);

  const boardLight2 = new PointLight(0xff00ff, 1, 4);
  boardLight2.position.set(-1, 2, -2);
  world.scene.add(boardLight2);

  const boardLight3 = new PointLight(0x00ff88, 1, 4);
  boardLight3.position.set(1, 2, -2);
  world.scene.add(boardLight3);

  // Neon grid floor
  const floorGeo = new PlaneGeometry(30, 30);
  const floorMat = new MeshStandardMaterial({
    color: '#050510',
    emissive: new Color('#050510'),
    emissiveIntensity: 0.2,
    roughness: 0.9,
    side: DoubleSide,
  });
  const floor = new Mesh(floorGeo, floorMat);
  floor.rotation.x = -Math.PI / 2;
  floor.position.y = 0;
  world.scene.add(floor);

  // Grid lines on floor
  const gridGroup = new Group();
  const gridMat = new LineBasicMaterial({ color: '#00ffff', transparent: true, opacity: 0.1 });
  for (let i = -15; i <= 15; i++) {
    const geo = new BoxGeometry(0.002, 0.001, 30);
    const mat = new MeshBasicMaterial({ color: '#00ffff', transparent: true, opacity: 0.08 });
    const line = new Mesh(geo, mat);
    line.position.set(i, 0.001, 0);
    gridGroup.add(line);

    const line2 = new Mesh(geo.clone(), mat);
    line2.rotation.y = Math.PI / 2;
    line2.position.set(0, 0.001, i);
    gridGroup.add(line2);
  }
  world.scene.add(gridGroup);

  // Neon grid ceiling
  const ceilGeo = new PlaneGeometry(30, 30);
  const ceilMat = new MeshStandardMaterial({
    color: '#020208',
    emissive: new Color('#020208'),
    emissiveIntensity: 0.1,
    side: DoubleSide,
  });
  const ceiling = new Mesh(ceilGeo, ceilMat);
  ceiling.rotation.x = Math.PI / 2;
  ceiling.position.y = 4;
  world.scene.add(ceiling);

  // Ceiling grid
  const ceilGridGroup = new Group();
  for (let i = -15; i <= 15; i += 2) {
    const geo = new BoxGeometry(0.002, 0.001, 30);
    const mat = new MeshBasicMaterial({ color: '#0088ff', transparent: true, opacity: 0.05 });
    const line = new Mesh(geo, mat);
    line.position.set(i, 3.999, 0);
    ceilGridGroup.add(line);

    const line2 = new Mesh(geo.clone(), mat);
    line2.rotation.y = Math.PI / 2;
    line2.position.set(0, 3.999, i);
    ceilGridGroup.add(line2);
  }
  world.scene.add(ceilGridGroup);

  // Back wall behind dartboard
  const wallGeo = new PlaneGeometry(6, 4);
  const wallMat = new MeshStandardMaterial({
    color: '#060612',
    emissive: new Color('#060612'),
    emissiveIntensity: 0.2,
    side: DoubleSide,
  });
  const wall = new Mesh(wallGeo, wallMat);
  wall.position.set(0, 2, -2.5);
  world.scene.add(wall);

  // Wall border glow
  const wallBorderGeo = new BoxGeometry(6.05, 4.05, 0.01);
  const wallBorderMat = new MeshBasicMaterial({
    color: '#00ffff',
    transparent: true,
    opacity: 0.15,
    blending: AdditiveBlending,
  });
  const wallBorder = new Mesh(wallBorderGeo, wallBorderMat);
  wallBorder.position.set(0, 2, -2.49);
  world.scene.add(wallBorder);

  // Throw line (oche) — glowing line on the floor
  const ocheGeo = new BoxGeometry(0.6, 0.005, 0.02);
  const ocheMat = new MeshBasicMaterial({
    color: '#ff00ff',
    transparent: true,
    opacity: 0.8,
  });
  const oche = new Mesh(ocheGeo, ocheMat);
  oche.position.set(0, 0.003, -0.01);
  world.scene.add(oche);

  // Oche glow
  const ocheGlowGeo = new BoxGeometry(0.65, 0.005, 0.06);
  const ocheGlowMat = new MeshBasicMaterial({
    color: '#ff00ff',
    transparent: true,
    opacity: 0.15,
    blending: AdditiveBlending,
  });
  const ocheGlow = new Mesh(ocheGlowGeo, ocheGlowMat);
  ocheGlow.position.set(0, 0.002, -0.01);
  world.scene.add(ocheGlow);

  // Floating wireframe decorations
  const decorations: { mesh: Mesh; speed: number; axis: Vector3 }[] = [];
  const decoTypes = [
    () => new TorusGeometry(0.15, 0.03, 8, 16),
    () => new BoxGeometry(0.2, 0.2, 0.2),
    () => new SphereGeometry(0.12, 8, 8),
    () => new ConeGeometry(0.12, 0.25, 6),
  ];
  const decoColors = ['#00ffff', '#ff00ff', '#00ff88', '#ffff00', '#ff6600'];

  for (let i = 0; i < 16; i++) {
    const geoFn = decoTypes[i % decoTypes.length];
    const geo = geoFn();
    const color = decoColors[i % decoColors.length];
    const edges = new EdgesGeometry(geo);
    const mat = new LineBasicMaterial({ color, transparent: true, opacity: 0.3 });
    const wireframe = new LineSegments(edges, mat) as any as Mesh;

    const x = (Math.random() - 0.5) * 12;
    const y = 0.5 + Math.random() * 3;
    const z = -5 + Math.random() * 8;
    wireframe.position.set(x, y, z);

    world.scene.add(wireframe);
  }

  // Ambient floating particles
  const particleGroup = new Group();
  for (let i = 0; i < 50; i++) {
    const geo = new SphereGeometry(0.005, 4, 4);
    const color = decoColors[i % decoColors.length];
    const mat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.3 + Math.random() * 0.3,
    });
    const particle = new Mesh(geo, mat);
    particle.position.set(
      (Math.random() - 0.5) * 15,
      Math.random() * 4,
      (Math.random() - 0.5) * 15
    );
    particleGroup.add(particle);
  }
  world.scene.add(particleGroup);

  // Side pillars for atmosphere
  for (let side = -1; side <= 1; side += 2) {
    const pillarGeo = new CylinderGeometry(0.05, 0.05, 4, 8);
    const pillarMat = new MeshStandardMaterial({
      color: '#111122',
      emissive: new Color('#00ffff'),
      emissiveIntensity: 0.1,
    });
    const pillar = new Mesh(pillarGeo, pillarMat);
    pillar.position.set(side * 1.5, 2, -2.5);
    world.scene.add(pillar);

    // Pillar top glow
    const topGeo = new SphereGeometry(0.08, 8, 8);
    const topMat = new MeshBasicMaterial({
      color: '#00ffff',
      transparent: true,
      opacity: 0.4,
    });
    const topGlow = new Mesh(topGeo, topMat);
    topGlow.position.set(side * 1.5, 4, -2.5);
    world.scene.add(topGlow);
  }
}

// Achievement system
import { GameManager, GameMode } from './game';
import { ScoreResult } from './dartboard';
import { StatsTracker } from './stats';

export interface Achievement {
  id: string;
  name: string;
  description: string;
  unlocked: boolean;
}

const ACHIEVEMENTS_KEY = 'neon-darts-achievements';

export class AchievementManager {
  achievements: Achievement[] = [
    { id: 'first-game', name: 'First Steps', description: 'Complete your first game', unlocked: false },
    { id: 'bullseye', name: 'Bulls Eye!', description: 'Hit the bullseye', unlocked: false },
    { id: 'triple-20', name: 'Top Score', description: 'Hit a triple 20', unlocked: false },
    { id: 'one-eighty', name: '180!', description: 'Score 180 in a single turn', unlocked: false },
    { id: 'first-win', name: 'Winner!', description: 'Win your first game', unlocked: false },
    { id: 'hat-trick', name: 'Hat Trick', description: 'Hit 3 bullseyes in one turn', unlocked: false },
    { id: 'five-wins', name: 'Regular', description: 'Win 5 games', unlocked: false },
    { id: 'ten-wins', name: 'Veteran', description: 'Win 10 games', unlocked: false },
    { id: 'cricket-closer', name: 'Cricket Closer', description: 'Win a game of Cricket', unlocked: false },
    { id: 'shanghai', name: 'Shanghai!', description: 'Hit single, double, and triple of same number in one turn', unlocked: false },
    { id: 'clock-master', name: 'Clock Master', description: 'Win Around the Clock', unlocked: false },
    { id: 'perfect-leg', name: 'Perfect Leg', description: 'Finish 501 in 9 darts or less', unlocked: false },
    { id: 'accuracy-80', name: 'Sharpshooter', description: 'Achieve 80%+ accuracy in a game', unlocked: false },
    { id: 'all-doubles', name: 'Double or Nothing', description: 'Hit all 20 doubles', unlocked: false },
    { id: 'hundred-games', name: 'Centurion', description: 'Play 100 games', unlocked: false },
    { id: 'ton-plus', name: 'Ton Plus', description: 'Score 100+ in a single turn', unlocked: false },
    { id: 'no-miss-turn', name: 'Precision', description: 'Complete 10 turns with no misses', unlocked: false },
    { id: 'triple-triple', name: 'Triple Threat', description: 'Hit 3 triples in one turn', unlocked: false },
    { id: 'beat-hard-ai', name: 'AI Slayer', description: 'Beat the Hard AI', unlocked: false },
    { id: 'all-modes', name: 'Versatile', description: 'Win in all 4 game modes', unlocked: false },
  ];

  private stats: StatsTracker;
  public onUnlock: ((achievement: Achievement) => void) | null = null;

  constructor(stats: StatsTracker) {
    this.stats = stats;
    this.load();
  }

  private load() {
    try {
      const saved = localStorage.getItem(ACHIEVEMENTS_KEY);
      if (saved) {
        const unlocked: string[] = JSON.parse(saved);
        for (const a of this.achievements) {
          a.unlocked = unlocked.includes(a.id);
        }
      }
    } catch {}
  }

  private save() {
    try {
      const unlocked = this.achievements.filter(a => a.unlocked).map(a => a.id);
      localStorage.setItem(ACHIEVEMENTS_KEY, JSON.stringify(unlocked));
    } catch {}
  }

  unlock(id: string) {
    const achievement = this.achievements.find(a => a.id === id);
    if (achievement && !achievement.unlocked) {
      achievement.unlocked = true;
      this.save();
      if (this.onUnlock) this.onUnlock(achievement);
    }
  }

  checkAll(game: GameManager, result: ScoreResult | null) {
    const s = this.stats.stats;

    // Throw-based
    if (result) {
      if (result.segment === 25 && result.multiplier === 2) this.unlock('bullseye');
      if (result.segment === 20 && result.multiplier === 3) this.unlock('triple-20');
      if (result.total >= 100) this.unlock('ton-plus');
    }

    // Turn-based
    if (game.currentTurnThrows.length === 3) {
      const turnTotal = game.currentTurnThrows.reduce((sum, t) => sum + t.total, 0);
      if (turnTotal === 180) this.unlock('one-eighty');
      if (turnTotal >= 100) this.unlock('ton-plus');

      const allBulls = game.currentTurnThrows.every(t => t.segment === 25 && t.multiplier === 2);
      if (allBulls) this.unlock('hat-trick');

      const allTriples = game.currentTurnThrows.every(t => t.multiplier === 3);
      if (allTriples) this.unlock('triple-triple');
    }

    // Game-based
    if (game.isGameOver()) {
      this.unlock('first-game');
      if (game.getWinner() === 1) {
        this.unlock('first-win');
        if (game.mode === GameMode.Cricket) this.unlock('cricket-closer');
        if (game.mode === GameMode.AroundTheClock) this.unlock('clock-master');
      }
    }

    // Stats-based
    if (s.gamesWon >= 5) this.unlock('five-wins');
    if (s.gamesWon >= 10) this.unlock('ten-wins');
    if (s.gamesPlayed >= 100) this.unlock('hundred-games');
    if (s.oneEighties > 0) this.unlock('one-eighty');

    // Check all modes won
    if (s.fiveOhOneWins > 0 && s.cricketWins > 0 && s.shanghaiWins > 0 && s.aroundTheClockWins > 0) {
      this.unlock('all-modes');
    }
  }

  getUnlockedCount(): number {
    return this.achievements.filter(a => a.unlocked).length;
  }

  getTotalCount(): number {
    return this.achievements.length;
  }
}

// AI opponent logic
import { GameManager, GameMode } from './game';
import { BOARD_SEGMENTS } from './dartboard';

export enum AIDifficulty {
  Easy = 'easy',
  Medium = 'medium',
  Hard = 'hard',
}

interface TargetPosition {
  x: number;
  y: number;
}

export class AIOpponent {
  difficulty: AIDifficulty = AIDifficulty.Medium;

  private getNoiseAmount(): number {
    switch (this.difficulty) {
      case AIDifficulty.Easy: return 0.045;
      case AIDifficulty.Medium: return 0.025;
      case AIDifficulty.Hard: return 0.012;
    }
  }

  getTarget(game: GameManager): TargetPosition {
    switch (game.mode) {
      case GameMode.FiveOhOne:
        return this.get501Target(game);
      case GameMode.Cricket:
        return this.getCricketTarget(game);
      case GameMode.AroundTheClock:
        return this.getAroundTheClockTarget(game);
      case GameMode.Shanghai:
        return this.getShanghaiTarget(game);
      default:
        return { x: 0, y: 0 };
    }
  }

  private get501Target(game: GameManager): TargetPosition {
    const player = game.players[game.currentPlayer];
    const remaining = player.remaining501 || 0;

    // If can finish on a double
    if (remaining <= 40 && remaining % 2 === 0) {
      const doubleNeeded = remaining / 2;
      return this.getSegmentPosition(doubleNeeded, 'double');
    }

    // If remaining is 50 — aim for bullseye
    if (remaining === 50) {
      return { x: 0, y: 0 };
    }

    // Otherwise aim for high-value targets
    // T20 is the most efficient
    if (remaining > 60) {
      return this.getSegmentPosition(20, 'triple');
    }

    // Set up for a double finish
    const targetScore = remaining - (remaining % 2 === 0 ? remaining : remaining - 1);
    if (targetScore > 0 && targetScore <= 20) {
      return this.getSegmentPosition(targetScore, 'single');
    }

    return this.getSegmentPosition(20, 'triple');
  }

  private getCricketTarget(game: GameManager): TargetPosition {
    const player = game.players[game.currentPlayer];
    const marks = player.cricketMarks!;

    // Find unclosed numbers, prioritize higher numbers
    const cricketNums = [20, 19, 18, 17, 16, 15, 25];
    for (const num of cricketNums) {
      if (marks[num] < 3) {
        return num === 25
          ? { x: 0, y: 0 }
          : this.getSegmentPosition(num, 'triple');
      }
    }

    // All closed — aim for scoring on opponent's open numbers
    const opponent = game.players[1 - game.currentPlayer];
    const oppMarks = opponent.cricketMarks!;
    for (const num of cricketNums) {
      if (oppMarks[num] < 3) {
        return num === 25
          ? { x: 0, y: 0 }
          : this.getSegmentPosition(num, 'triple');
      }
    }

    return { x: 0, y: 0 };
  }

  private getAroundTheClockTarget(game: GameManager): TargetPosition {
    const player = game.players[game.currentPlayer];
    const target = player.currentTarget || 1;
    return this.getSegmentPosition(target, 'single');
  }

  private getShanghaiTarget(game: GameManager): TargetPosition {
    // Aim for triple of the current round number
    return this.getSegmentPosition(game.round, 'triple');
  }

  private getSegmentPosition(segment: number, ring: 'single' | 'double' | 'triple'): TargetPosition {
    if (segment === 25) {
      return { x: 0, y: 0 }; // Bullseye center
    }

    const segIndex = BOARD_SEGMENTS.indexOf(segment);
    if (segIndex === -1) return { x: 0, y: 0 };

    const segmentAngle = (Math.PI * 2) / 20;
    const angle = segIndex * segmentAngle - Math.PI / 2;

    let radius: number;
    switch (ring) {
      case 'double': radius = 0.166; break;
      case 'triple': radius = 0.103; break;
      default: radius = 0.135; break; // single (outer single area)
    }

    return {
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius,
    };
  }

  applyNoise(x: number, y: number): { x: number; y: number } {
    const noise = this.getNoiseAmount();
    return {
      x: x + (Math.random() - 0.5) * noise * 2,
      y: y + (Math.random() - 0.5) * noise * 2,
    };
  }
}

// Effects manager — particles, hit effects
import {
  World,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Color,
  Vector3,
  AdditiveBlending,
  Group,
} from '@iwsdk/core';

interface Particle {
  mesh: Mesh;
  velocity: Vector3;
  life: number;
  maxLife: number;
}

const MAX_PARTICLES = 80;

export class EffectsManager {
  private world: World;
  private particles: Particle[] = [];
  private particleGroup: Group;
  private sharedGeo = new SphereGeometry(0.004, 4, 4);

  constructor(world: World) {
    this.world = world;
    this.particleGroup = new Group();
    world.scene.add(this.particleGroup);
  }

  spawnHitParticles(position: Vector3, color: string, count = 12) {
    for (let i = 0; i < count && this.particles.length < MAX_PARTICLES; i++) {
      const mat = new MeshBasicMaterial({
        color,
        transparent: true,
        opacity: 0.8,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(this.sharedGeo, mat);
      mesh.position.copy(position);
      this.particleGroup.add(mesh);

      const speed = 0.3 + Math.random() * 0.5;
      const angle = Math.random() * Math.PI * 2;
      const elevation = (Math.random() - 0.3) * Math.PI;

      this.particles.push({
        mesh,
        velocity: new Vector3(
          Math.cos(angle) * Math.cos(elevation) * speed,
          Math.sin(elevation) * speed + 0.2,
          Math.sin(angle) * Math.cos(elevation) * speed * 0.3
        ),
        life: 0.6 + Math.random() * 0.4,
        maxLife: 0.6 + Math.random() * 0.4,
      });
    }
  }

  update(dt: number) {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= dt;

      if (p.life <= 0) {
        this.particleGroup.remove(p.mesh);
        (p.mesh.material as MeshBasicMaterial).dispose();
        this.particles.splice(i, 1);
        continue;
      }

      p.velocity.y -= 1.5 * dt; // gravity
      p.mesh.position.add(p.velocity.clone().multiplyScalar(dt));

      const alpha = p.life / p.maxLife;
      (p.mesh.material as MeshBasicMaterial).opacity = alpha * 0.8;
    }
  }
}

// Dart skin system — multiple dart visual styles
import {
  Group,
  Mesh,
  CylinderGeometry,
  ConeGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Color,
  AdditiveBlending,
} from '@iwsdk/core';

export interface DartSkin {
  id: string;
  name: string;
  barrelColor: string;
  tipColor: string;
  flightColor: string;
  glowColor: string;
  emissiveIntensity: number;
  metalness: number;
}

export const DART_SKINS: DartSkin[] = [
  {
    id: 'neon-classic',
    name: 'Neon Classic',
    barrelColor: '#00ffff',
    tipColor: '#ffffff',
    flightColor: '#ff00ff',
    glowColor: '#00ffff',
    emissiveIntensity: 0.6,
    metalness: 0.8,
  },
  {
    id: 'fire',
    name: 'Inferno',
    barrelColor: '#ff4400',
    tipColor: '#ffcc00',
    flightColor: '#ff0000',
    glowColor: '#ff6600',
    emissiveIntensity: 0.8,
    metalness: 0.6,
  },
  {
    id: 'ice',
    name: 'Frost Bite',
    barrelColor: '#88ccff',
    tipColor: '#ffffff',
    flightColor: '#4488ff',
    glowColor: '#aaddff',
    emissiveIntensity: 0.5,
    metalness: 0.9,
  },
  {
    id: 'gold',
    name: 'Golden Arrow',
    barrelColor: '#ffcc00',
    tipColor: '#ffffff',
    flightColor: '#ff9900',
    glowColor: '#ffdd44',
    emissiveIntensity: 0.7,
    metalness: 1.0,
  },
  {
    id: 'phantom',
    name: 'Phantom',
    barrelColor: '#9933ff',
    tipColor: '#cc88ff',
    flightColor: '#6600cc',
    glowColor: '#aa44ff',
    emissiveIntensity: 0.6,
    metalness: 0.7,
  },
  {
    id: 'toxic',
    name: 'Toxic Surge',
    barrelColor: '#00ff44',
    tipColor: '#ccffcc',
    flightColor: '#00cc00',
    glowColor: '#44ff88',
    emissiveIntensity: 0.7,
    metalness: 0.5,
  },
];

const SKINS_KEY = 'neon-darts-skin';

export class DartSkinManager {
  currentSkin: DartSkin;

  constructor() {
    const savedId = this.loadSkin();
    this.currentSkin = DART_SKINS.find(s => s.id === savedId) || DART_SKINS[0];
  }

  private loadSkin(): string {
    try {
      return localStorage.getItem(SKINS_KEY) || 'neon-classic';
    } catch {
      return 'neon-classic';
    }
  }

  setSkin(id: string) {
    const skin = DART_SKINS.find(s => s.id === id);
    if (skin) {
      this.currentSkin = skin;
      try { localStorage.setItem(SKINS_KEY, id); } catch {}
    }
  }

  nextSkin() {
    const idx = DART_SKINS.indexOf(this.currentSkin);
    this.setSkin(DART_SKINS[(idx + 1) % DART_SKINS.length].id);
  }

  prevSkin() {
    const idx = DART_SKINS.indexOf(this.currentSkin);
    this.setSkin(DART_SKINS[(idx - 1 + DART_SKINS.length) % DART_SKINS.length].id);
  }

  createDartMesh(): Group {
    const skin = this.currentSkin;
    const group = new Group();

    // Barrel
    const barrelGeo = new CylinderGeometry(0.003, 0.004, 0.05, 8);
    const barrelMat = new MeshStandardMaterial({
      color: skin.barrelColor,
      emissive: new Color(skin.barrelColor),
      emissiveIntensity: skin.emissiveIntensity,
      metalness: skin.metalness,
      roughness: 0.2,
    });
    const barrel = new Mesh(barrelGeo, barrelMat);
    barrel.rotation.x = Math.PI / 2;
    group.add(barrel);

    // Tip
    const tipGeo = new ConeGeometry(0.003, 0.02, 8);
    const tipMat = new MeshStandardMaterial({
      color: skin.tipColor,
      emissive: new Color(skin.tipColor),
      emissiveIntensity: 0.4,
      metalness: 0.9,
    });
    const tip = new Mesh(tipGeo, tipMat);
    tip.rotation.x = -Math.PI / 2;
    tip.position.z = -0.035;
    group.add(tip);

    // Flights
    for (let i = 0; i < 4; i++) {
      const flightGeo = new CylinderGeometry(0, 0.008, 0.02, 3);
      const flightMat = new MeshBasicMaterial({
        color: skin.flightColor,
        transparent: true,
        opacity: 0.7,
        side: 2, // DoubleSide
      });
      const flight = new Mesh(flightGeo, flightMat);
      flight.rotation.x = Math.PI / 2;
      flight.rotation.z = (i / 4) * Math.PI * 2;
      flight.position.z = 0.03;
      group.add(flight);
    }

    // Glow
    const glowGeo = new CylinderGeometry(0.008, 0.008, 0.06, 8);
    const glowMat = new MeshBasicMaterial({
      color: skin.glowColor,
      transparent: true,
      opacity: 0.15,
      blending: AdditiveBlending,
    });
    const glowMesh = new Mesh(glowGeo, glowMat);
    glowMesh.rotation.x = Math.PI / 2;
    group.add(glowMesh);

    return group;
  }
}

// Statistics tracker
export interface GameStats {
  gamesPlayed: number;
  gamesWon: number;
  totalDartsThrown: number;
  bullseyes: number;
  triples: number;
  doubles: number;
  misses: number;
  highestSingleTurn: number;
  oneEighties: number; // 3x T20 = 180
  bestGameBy501: number; // least darts to finish
  cricketWins: number;
  shanghaiWins: number;
  aroundTheClockWins: number;
  fiveOhOneWins: number;
  totalScore: number;
  perfectLegs: number; // 501 in 9 darts or less
}

const STATS_KEY = 'neon-darts-stats';

export class StatsTracker {
  stats: GameStats;

  constructor() {
    this.stats = this.load();
  }

  private load(): GameStats {
    try {
      const saved = localStorage.getItem(STATS_KEY);
      if (saved) return JSON.parse(saved);
    } catch {}
    return {
      gamesPlayed: 0,
      gamesWon: 0,
      totalDartsThrown: 0,
      bullseyes: 0,
      triples: 0,
      doubles: 0,
      misses: 0,
      highestSingleTurn: 0,
      oneEighties: 0,
      bestGameBy501: 999,
      cricketWins: 0,
      shanghaiWins: 0,
      aroundTheClockWins: 0,
      fiveOhOneWins: 0,
      totalScore: 0,
      perfectLegs: 0,
    };
  }

  save() {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(this.stats));
    } catch {}
  }

  recordThrow(total: number, multiplier: number, segment: number) {
    this.stats.totalDartsThrown++;
    this.stats.totalScore += total;
    if (total === 0) this.stats.misses++;
    if (segment === 25 && multiplier === 2) this.stats.bullseyes++;
    if (multiplier === 3) this.stats.triples++;
    if (multiplier === 2 && segment !== 25) this.stats.doubles++;
    this.save();
  }

  recordTurn(turnScore: number) {
    if (turnScore > this.stats.highestSingleTurn) {
      this.stats.highestSingleTurn = turnScore;
    }
    if (turnScore === 180) this.stats.oneEighties++;
    this.save();
  }

  recordGame(mode: string, won: boolean) {
    this.stats.gamesPlayed++;
    if (won) {
      this.stats.gamesWon++;
      switch (mode) {
        case '501': this.stats.fiveOhOneWins++; break;
        case 'cricket': this.stats.cricketWins++; break;
        case 'shanghai': this.stats.shanghaiWins++; break;
        case 'around-the-clock': this.stats.aroundTheClockWins++; break;
      }
    }
    this.save();
  }

  getWinRate(): number {
    if (this.stats.gamesPlayed === 0) return 0;
    return Math.round((this.stats.gamesWon / this.stats.gamesPlayed) * 100);
  }

  getAccuracy(): number {
    if (this.stats.totalDartsThrown === 0) return 0;
    const hits = this.stats.totalDartsThrown - this.stats.misses;
    return Math.round((hits / this.stats.totalDartsThrown) * 100);
  }

  getAverageScore(): number {
    if (this.stats.totalDartsThrown === 0) return 0;
    return Math.round((this.stats.totalScore / this.stats.totalDartsThrown) * 3); // per turn
  }
}

// Combo system — tracks consecutive high-scoring throws
export interface ComboState {
  count: number;
  multiplier: number;
  lastScore: number;
  active: boolean;
  label: string;
}

const COMBO_THRESHOLDS = [
  { min: 40, label: 'NICE!', multiplier: 1.0 },
  { min: 60, label: 'GREAT!', multiplier: 1.0 },
  { min: 100, label: 'AMAZING!', multiplier: 1.0 },
  { min: 140, label: 'INCREDIBLE!', multiplier: 1.0 },
  { min: 180, label: 'PERFECT!', multiplier: 1.0 },
];

export class ComboTracker {
  private consecutiveGoodThrows = 0;
  private consecutiveGoodTurns = 0;

  // Called after each individual dart hit
  onThrow(score: number): ComboState | null {
    if (score >= 40) {
      this.consecutiveGoodThrows++;
    } else if (score === 0) {
      this.consecutiveGoodThrows = 0;
    }

    // Single throw feedback
    if (score >= 40) {
      const tier = COMBO_THRESHOLDS.filter(t => score >= t.min).pop();
      if (tier) {
        return {
          count: this.consecutiveGoodThrows,
          multiplier: tier.multiplier,
          lastScore: score,
          active: true,
          label: this.consecutiveGoodThrows >= 3
            ? `${tier.label} x${this.consecutiveGoodThrows} STREAK`
            : tier.label,
        };
      }
    }
    return null;
  }

  // Called after each turn (3 darts)
  onTurnEnd(turnScore: number): ComboState | null {
    if (turnScore >= 60) {
      this.consecutiveGoodTurns++;
      if (this.consecutiveGoodTurns >= 2) {
        return {
          count: this.consecutiveGoodTurns,
          multiplier: 1.0,
          lastScore: turnScore,
          active: true,
          label: `${this.consecutiveGoodTurns} TURN STREAK!`,
        };
      }
    } else {
      this.consecutiveGoodTurns = 0;
    }
    return null;
  }

  reset() {
    this.consecutiveGoodThrows = 0;
    this.consecutiveGoodTurns = 0;
  }
}

