{"content":"// Aim Cursor — visual crosshair/reticle on the dartboard
import {
  World,
  Group,
  Mesh,
  RingGeometry,
  CircleGeometry,
  MeshBasicMaterial,
  AdditiveBlending,
  DoubleSide,
  Color,
  Vector3,
} from '@iwsdk/core';

export class AimCursor {
  private world: World;
  private group: Group;
  private outerRing: Mesh;
  private innerDot: Mesh;
  private pulseTime = 0;
  public visible = false;

  constructor(world: World) {
    this.world = world;
    this.group = new Group();

    // Outer ring
    const ringGeo = new RingGeometry(0.008, 0.01, 32);
    const ringMat = new MeshBasicMaterial({
      color: '#00ffff',
      transparent: true,
      opacity: 0.6,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    this.outerRing = new Mesh(ringGeo, ringMat);
    this.group.add(this.outerRing);

    // Inner dot
    const dotGeo = new CircleGeometry(0.002, 16);
    const dotMat = new MeshBasicMaterial({
      color: '#ffffff',
      transparent: true,
      opacity: 0.8,
      side: DoubleSide,
    });
    this.innerDot = new Mesh(dotGeo, dotMat);
    this.innerDot.position.z = 0.001;
    this.group.add(this.innerDot);

    // Crosshair lines — 4 short lines
    const lineLen = 0.015;
    const lineWidth = 0.001;
    const directions = [
      { x: 0, y: lineLen / 2 + 0.012 },  // up
      { x: 0, y: -(lineLen / 2 + 0.012) }, // down
      { x: lineLen / 2 + 0.012, y: 0 },  // right
      { x: -(lineLen / 2 + 0.012), y: 0 }, // left
    ];

    for (const dir of directions) {
      const geo = dir.x === 0
        ? new RingGeometry(0, lineWidth / 2, 4, 1, 0, Math.PI * 2)
        : new RingGeometry(0, lineWidth / 2, 4, 1, 0, Math.PI * 2);
      // Use a thin box instead
      const boxGeo = dir.x === 0
        ? new (await_box_import())(lineWidth, lineLen, 0.001)
        : new (await_box_import())(lineLen, lineWidth, 0.001);
      // Simpler: just use the dot
    }

    this.group.visible = false;
    world.scene.add(this.group);
  }

  setPosition(boardPos: Vector3, aimX: number, aimY: number) {
    this.group.position.set(
      boardPos.x + aimX,
      boardPos.y + aimY,
      boardPos.z + 0.015
    );
  }

  show() {
    this.group.visible = true;
    this.visible = true;
  }

  hide() {
    this.group.visible = false;
    this.visible = false;
  }

  update(dt: number) {
    if (!this.visible) return;

    this.pulseTime += dt * 3;
    const pulse = 0.8 + Math.sin(this.pulseTime) * 0.2;

    (this.outerRing.material as MeshBasicMaterial).opacity = 0.4 + pulse * 0.3;

    const scale = 0.9 + Math.sin(this.pulseTime * 0.7) * 0.15;
    this.outerRing.scale.set(scale, scale, 1);
  }
}
